GeminiService.instance = new GeminiService();
}
return GeminiService.instance;
}
public async transformToDoodle(
imageBase64: string,
mimeType: string,
palette: ColorPalette
): Promise<string> {
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
code
