const fullPrompt = `Transform the provided image into a high-contrast, stylized digital vector illustration.
STYLE GUIDELINES:
CHARACTER STYLIZATION: The main subject/character must NOT look realistic. It should be redrawn as a crisp vector illustration with bold, clean ink outlines and stylized features. Use cel-shading or flat-color shading in shades of ${palette.shades}.
BACKGROUND DOODLES: Fill the ENTIRE background with an extremely dense, crowded composition of whimsical hand-drawn doodles (swirls, stars, flowers, abstract shapes).
PLACEMENT: CRITICAL! The doodles must be placed exclusively BEHIND the main subject. No doodles should overlap, obscure, or cover any part of the stylized character.
COLOR PALETTE: Use a monochromatic but vibrant "juicy" palette focused exclusively on shades of ${palette.shades}. Incorporate accents of ${palette.tertiary}.
FINAL OUTPUT: A clean, vibrant, high-resolution digital art piece. No photographic elements should remain; it must look like professional pop-art illustration.`;
const response = await ai.models.generateContent({
model: 'gemini-2.5-flash-image',
contents: {
parts: [{ inlineData: { data: imageBase64, mimeType } }, { text: fullPrompt }],
},
});
let resultImageUrl = '';
if (response.candidates?.[0]) {
for (const part of response.candidates[0].content.parts) {
if (part.inlineData) {
resultImageUrl = data:image/png;base64,${part.inlineData.data};
break;
}
}
}
if (!resultImageUrl) throw new Error("Model failed to generate output.");
return resultImageUrl;
}
}
