const palette = COLOR_PALETTES.find(c => c.id === selectedColorId)!;
const gemini = GeminiService.getInstance();
const newResults: ImageItem[] = selectedUploads.map(upload => ({
...upload,
id: res-${Date.now()}-${Math.random().toString(36).substr(2, 5)},
