import React, { useState, useRef } from 'react';
import { ImageItem } from '../types';
interface Props { onUpload: (items: ImageItem[]) => void; onWebcamClick: () => void; itemCount: number; }
export const ImageUploadArea: React.FC<Props> = ({ onUpload, onWebcamClick, itemCount }) => {
const fileInputRef = useRef<HTMLInputElement>(null);
const [isDragging, setIsDragging] = useState(false);
const processFiles = async (files: File[]) => {
const newItems = await Promise.all(files.map(file => new Promise<ImageItem>(resolve => {
const reader = new FileReader();
reader.onloadend = () => resolve({
id: Math.random().toString(36).substr(2, 9),
base64: (reader.result as string).split(',')[1],
mimeType: file.type,
name: file.name,
status: 'pending',
selected: true
});
reader.readAsDataURL(file);
})));
onUpload(newItems);
};
return (
<div className="space-y-4">
<div
onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
onDragLeave={() => setIsDragging(false)}
onDrop={(e) => { e.preventDefault(); setIsDragging(false); processFiles((Array.from(e.dataTransfer.files) as File[]).filter(f => f.type.startsWith('image/'))); }}
onClick={() => fileInputRef.current?.click()}
className={h-40 border-2 border-dashed rounded-2xl flex flex-col items-center justify-center transition-all cursor-pointer ${isDragging ? 'bg-indigo-50 border-indigo-500' : 'bg-slate-50'}}
>
<p className="font-bold text-slate-900">{isDragging ? 'Drop images here' : itemCount > 0 ? ${itemCount} Uploaded : 'Drag & Drop Images'}</p>
<input type="file" ref={fileInputRef} onChange={(e) => processFiles(Array.from(e.target.files || []) as File[])} className="hidden" accept="image/*" multiple />
</div>
<button onClick={onWebcamClick} className="w-full py-3 bg-white border rounded-xl font-bold flex items-center justify-center space-x-2">
<span>📸 Use Webcam</span>
</button>
</div>
);
};
