import React, { useRef, useState, useEffect } from 'react';
export const WebcamCapture: React.FC<{ onCapture: (b64: string) => void; onClose: () => void; }> = ({ onCapture, onClose }) => {
const videoRef = useRef<HTMLVideoElement>(null);
const canvasRef = useRef<HTMLCanvasElement>(null);
useEffect(() => {
navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } }).then(s => {
if (videoRef.current) videoRef.current.srcObject = s;
});
}, []);
return (
<div className="fixed inset-0 z-[100] bg-black/80 flex flex-col items-center justify-center p-4">
<div className="bg-white rounded-3xl overflow-hidden max-w-lg w-full">
<video ref={videoRef} autoPlay playsInline className="w-full aspect-square object-cover" />
<div className="p-6 flex justify-between items-center">
<button onClick={onClose} className="font-bold text-slate-500">Cancel</button>
<button onClick={() => {
const ctx = canvasRef.current?.getContext('2d');
if (ctx && videoRef.current) {
canvasRef.current!.width = videoRef.current.videoWidth;
canvasRef.current!.height = videoRef.current.videoHeight;
ctx.drawImage(videoRef.current, 0, 0);
onCapture(canvasRef.current!.toDataURL('image/png').split(',')[1]);
onClose();
}
}} className="w-16 h-16 bg-slate-900 rounded-full border-4 border-slate-100 shadow-xl"></button>
<div className="w-12"></div>
</div>
</div>
<canvas ref={canvasRef} className="hidden" />
</div>
);
};

