    palette: ColorPalette
  ): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Updated prompt: Keep subject original colors but as flat vector, use palette for doodles.
    const fullPrompt = `Transform the provided image into a high-contrast, stylized digital vector illustration.

STYLE GUIDELINES:
1. CHARACTER STYLIZATION: The main subject/character MUST be redrawn as a crisp vector illustration with bold, clean ink outlines. 
   CRITICAL COLOR RULE: Use flat vector colors that match the subject's ORIGINAL natural complexion and original color scheme. Do NOT color the subject with the doodle palette. 
   The subject should look like a clean graphic illustration of their real self.

2. BACKGROUND DOODLES: Fill the ENTIRE background with an extremely dense, crowded composition of whimsical hand-drawn doodles (swirls, stars, flowers, abstract shapes). 
   The doodles MUST use a monochromatic but vibrant palette focused exclusively on shades of ${palette.shades}. Incorporate accents of ${palette.tertiary}.

3. PLACEMENT: The doodles must be placed exclusively BEHIND the main subject. No doodles should overlap or obscure any part of the stylized character.

FINAL OUTPUT: A clean, vibrant, high-resolution digital art piece. No photographic textures should remain; it must look like professional pop-art vector illustration with a doodle backdrop.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: imageBase64, mimeType } },
          { text: fullPrompt }
        ],
      },
    });

    let resultImageUrl = '';
    if (response.candidates?.[0]) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          resultImageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    }

    if (!resultImageUrl) {
      throw new Error("Model failed to generate output image part.");
    }

    return resultImageUrl;
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { ImageItem } from '../types';

interface Props { 
  onUpload: (items: ImageItem[]) => void; 
  onWebcamClick: () => void; 
  itemCount: number; 
}

export const ImageUploadArea: React.FC<Props> = ({ onUpload, onWebcamClick, itemCount }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  const processFiles = async (files: File[]) => {
    const newItems = await Promise.all(
      files.map(file => new Promise<ImageItem>(resolve => {
        const reader = new FileReader();
        reader.onloadend = () => resolve({
          id: Math.random().toString(36).substr(2, 9),
          base64: (reader.result as string).split(',')[1],
          mimeType: file.type,
          name: file.name,
          status: 'pending',
          selected: true
        });
        reader.readAsDataURL(file);
      }))
    );
    onUpload(newItems);
  };

  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      const items = e.clipboardData?.items;
      if (!items) return;
      const files: File[] = [];
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const file = items[i].getAsFile();
          if (file) files.push(file);
        }
      }
      if (files.length > 0) processFiles(files);
    };

    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [onUpload]);

  return (
    <div className="space-y-4">
      <div
        onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
        onDragLeave={() => setIsDragging(false)}
        onDrop={(e) => { 
          e.preventDefault(); 
          setIsDragging(false); 
          const files = Array.from(e.dataTransfer.files).filter(f => f.type.startsWith('image/'));
          processFiles(files);
        }}
        onClick={() => fileInputRef.current?.click()}
        className={`h-48 border-2 border-dashed rounded-3xl flex flex-col items-center justify-center transition-all cursor-pointer group hover:border-indigo-400 hover:bg-indigo-50/30 ${
          isDragging ? 'bg-indigo-50 border-indigo-500 scale-[0.98]' : 'bg-slate-50 border-slate-200'
        }`}
      >
        <div className="mb-3 p-3 bg-white rounded-2xl shadow-sm border border-slate-100 group-hover:scale-110 transition-transform">
          <svg className="w-8 h-8 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
          </svg>
        </div>
        <p className="font-bold text-slate-700 text-sm">
          {isDragging ? 'Drop it here!' : 'Click, Drag, or Paste images'}
        </p>
        <p className="text-slate-400 text-xs mt-1">PNG, JPG up to 10MB</p>
        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={(e) => processFiles(Array.from(e.target.files || []) as File[])} 
          className="hidden" 
          accept="image/*" 
          multiple 
        />
      </div>
      <button 
        onClick={onWebcamClick} 
        className="w-full py-4 bg-white border border-slate-200 rounded-2xl font-bold flex items-center justify-center space-x-2 text-slate-700 hover:bg-slate-50 hover:shadow-sm transition-all active:scale-95"
      >
        <span>📸 Use Webcam</span>
      </button>
    </div>
  );
};

