import React, { useRef, useState, useEffect } from 'react';

export const WebcamCapture: React.FC<{ onCapture: (b64: string) => void; onClose: () => void; }> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);

  useEffect(() => {
    navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } })
      .then(s => {
        setStream(s);
        if (videoRef.current) videoRef.current.srcObject = s;
      })
      .catch(err => {
        console.error("Webcam access error:", err);
        onClose();
      });

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleCapture = () => {
    const ctx = canvasRef.current?.getContext('2d');
    if (ctx && videoRef.current) {
      canvasRef.current!.width = videoRef.current.videoWidth;
      canvasRef.current!.height = videoRef.current.videoHeight;
      ctx.drawImage(videoRef.current, 0, 0);
      const b64 = canvasRef.current!.toDataURL('image/png').split(',')[1];
      onCapture(b64);
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-900/95 backdrop-blur-md flex flex-col items-center justify-center p-4">
      <div className="bg-white rounded-[40px] overflow-hidden max-w-lg w-full shadow-2xl animate-in fade-in zoom-in duration-300">
        <div className="relative aspect-[4/3] bg-black">
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover scale-x-[-1]" />
          <div className="absolute top-4 left-1/2 -translate-x-1/2 px-3 py-1 bg-black/50 backdrop-blur rounded-full text-white text-[10px] font-bold uppercase tracking-widest">
            Live Preview
          </div>
        </div>
        <div className="p-8 flex justify-between items-center bg-white">
          <button onClick={onClose} className="text-sm font-bold text-slate-400 hover:text-slate-600 transition-colors px-4">Cancel</button>
          <button 
            onClick={handleCapture}
            className="w-20 h-20 bg-white rounded-full border-[6px] border-slate-900 shadow-xl flex items-center justify-center hover:scale-105 active:scale-95 transition-transform group"
          >
            <div className="w-14 h-14 bg-red-500 rounded-full group-hover:bg-red-400 transition-colors"></div>
          </button>
          <div className="w-16"></div>
        </div>
      </div>
      <p className="text-white/40 text-xs font-medium mt-6">Position yourself in the center and smile!</p>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Header } from './components/Header';
import { ImageUploadArea } from './components/ImageUploadArea';
import { ColorSelector } from './components/ColorSelector';
import { ResultDisplay } from './components/ResultDisplay';
import { ImageManager } from './components/ImageManager';
import { WebcamCapture } from './components/WebcamCapture';
import { GeminiService } from './services/geminiService';
import { AppStatus, ImageItem } from './types';
import { COLOR_PALETTES, APP_NAME } from './constants';

export default function App() {
  const [activeTab, setActiveTab] = useState<'manager' | 'gallery'>('manager');
  const [status, setStatus] = useState<AppStatus>('idle');
  const [items, setItems] = useState<ImageItem[]>([]);
  const [selectedColorIds, setSelectedColorIds] = useState<string[]>([COLOR_PALETTES[4].id]); // Default Blue
  const [isWebcamOpen, setIsWebcamOpen] = useState(false);

  const handleUpload = (newItems: ImageItem[]) => {
    setItems(prev => [...prev, ...newItems]);
    setActiveTab('manager');
  };

  const handleWebcamCapture = (base64: string) => {
    const newItem: ImageItem = {
      id: `cam-${Date.now()}`,
      base64,
      mimeType: 'image/png',
      name: `Capture ${new Date().toLocaleTimeString()}`,
      status: 'pending',
      selected: true
    };
    handleUpload([newItem]);
  };

  const toggleSelect = (id: string) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, selected: !item.selected } : item));
  };

  const handleToggleColor = (id: string) => {
    setSelectedColorIds(prev => {
      if (prev.includes(id)) {
        if (prev.length === 1) return prev; // Keep at least one
        return prev.filter(c => c !== id);
      }
      return [...prev, id];
    });
  };

  const handleBatchAction = (action: 'all' | 'none' | 'clear') => {
    if (action === 'all') setItems(prev => prev.map(i => i.isResult ? i : { ...i, selected: true }));
    else if (action === 'none') setItems(prev => prev.map(i => i.isResult ? i : { ...i, selected: false }));
    else if (action === 'clear') {
      setItems(prev => prev.filter(i => i.isResult));
      if (status === 'completed') setStatus('idle');
    }
  };

  const handleRandomizeColors = () => {
    const available = selectedColorIds.length > 0 ? selectedColorIds : COLOR_PALETTES.map(p => p.id);
    setItems(prev => prev.map(item => {
      if (item.selected && !item.isResult) {
        const randomId = available[Math.floor(Math.random() * available.length)];
        return { ...item, assignedColorId: randomId };
      }
      return item;
    }));
  };

  const uploads = useMemo(() => items.filter(i => !i.isResult), [items]);
  const galleryResults = useMemo(() => items.filter(i => i.isResult), [items]);
  const selectedUploads = useMemo(() => uploads.filter(i => i.selected), [uploads]);

  const handleGenerate = async () => {
    if (selectedUploads.length === 0) return;

    setStatus('processing');
    setActiveTab('gallery');

    const gemini = GeminiService.getInstance();

    // Create new result placeholders
    const newResults: ImageItem[] = selectedUploads.map(upload => {
      // If user hasn't randomized, pick the first from selection or a random one
      const assignedId = upload.assignedColorId || (selectedColorIds[Math.floor(Math.random() * selectedColorIds.length)]);
      return {
        ...upload,
        id: `res-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        status: 'pending',
        isResult: true,
        assignedColorId: assignedId,
        selected: false
      };
    });

    setItems(prev => [...prev, ...newResults]);

    // Sequentially process each generation to avoid model rate limits
    for (const resultEntry of newResults) {
      setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'processing' } : it));

      const palette = COLOR_PALETTES.find(c => c.id === resultEntry.assignedColorId) || COLOR_PALETTES[0];

      try {
        const generatedUrl = await gemini.transformToDoodle(resultEntry.base64, resultEntry.mimeType, palette);
        setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'success', resultUrl: generatedUrl } : it));
      } catch (err) {
        console.error("Art generation failed:", err);
        setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'error', error: String(err) } : it));
      }
    }

    setStatus('completed');
  };

  return (
    <div className="min-h-screen pb-32">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* Controls Panel */}
          <section className="lg:col-span-4 flex flex-col space-y-6 lg:sticky lg:top-32">
            <div className="bg-white p-6 sm:p-8 rounded-[40px] shadow-sm border border-slate-100">
              <h2 className="text-xl font-jakarta font-bold mb-6 flex items-center">
                <span className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center text-sm mr-3">1</span>
                Add Images
              </h2>
              <ImageUploadArea onUpload={handleUpload} onWebcamClick={() => setIsWebcamOpen(true)} itemCount={uploads.length} />
            </div>

            <div className="bg-white p-6 sm:p-8 rounded-[40px] shadow-sm border border-slate-100">
              <h2 className="text-xl font-jakarta font-bold mb-2 flex items-center">
                <span className="w-8 h-8 rounded-full bg-purple-100 text-purple-600 flex items-center justify-center text-sm mr-3">2</span>
                Choose Palettes
              </h2>
              <p className="text-xs text-slate-400 mb-6 font-medium">Select multiple to randomize during generation.</p>
              <ColorSelector selectedIds={selectedColorIds} onToggle={handleToggleColor} disabled={status === 'processing'} />

              <button 
                onClick={handleRandomizeColors}
                disabled={selectedUploads.length === 0 || status === 'processing'}
                className="mt-6 w-full py-3 px-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-600 hover:bg-slate-100 transition-all flex items-center justify-center space-x-2 disabled:opacity-50"
              >
                <span>🔀 Pre-assign Random Colors</span>
              </button>
            </div>

            <button
              onClick={handleGenerate}
              disabled={selectedUploads.length === 0 || status === 'processing'}
              className={`w-full py-6 rounded-3xl font-extrabold text-xl text-white shadow-xl transition-all active:scale-95 disabled:bg-slate-200 disabled:shadow-none ${
                status === 'processing' ? 'animate-pulse cursor-wait' : ''
              }`}
              style={{ 
                backgroundColor: selectedUploads.length > 0 
                  ? (COLOR_PALETTES.find(c => c.id === selectedColorIds[0])?.hex || '#6366f1') 
                  : '#cbd5e1' 
              }}
            >
              {status === 'processing' ? 'Processing...' : `Generate ${selectedUploads.length} Artworks`}
            </button>
          </section>

          {/* Viewer Panel */}
          <section className="lg:col-span-8">
            <div className="bg-white p-6 sm:p-10 rounded-[40px] shadow-2xl shadow-indigo-100 min-h-[700px] border border-slate-50">
              <div className="flex items-center space-x-3 mb-10 bg-slate-100/50 p-2 rounded-2xl w-fit">
                <button 
                  onClick={() => setActiveTab('manager')} 
                  className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${
                    activeTab === 'manager' ? 'bg-white text-slate-900 shadow-md transform scale-105' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  Uploads
                </button>
                <button 
                  onClick={() => setActiveTab('gallery')} 
                  className={`px-6 py-2.5 rounded-xl text-sm font-bold transition-all relative ${
                    activeTab === 'gallery' ? 'bg-white text-slate-900 shadow-md transform scale-105' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  Gallery
                  {galleryResults.length > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-4 w-4">
