import { GoogleGenAI } from "@google/genai";
import { ColorPalette } from "../types";

export class GeminiService {
  private static instance: GeminiService;
  private constructor() {}

  public static getInstance(): GeminiService {
    if (!GeminiService.instance) {
      GeminiService.instance = new GeminiService();
    }
    return GeminiService.instance;
  }

  public async transformToDoodle(
    imageBase64: string,
    mimeType: string,
    palette: ColorPalette
  ): Promise<string> {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const fullPrompt = `Transform the provided image into a high-contrast pop-art digital vector illustration.

STYLE REQUIREMENTS:
1. THE SUBJECT: Redraw the main person/subject as a crisp vector illustration with bold, clean ink outlines. 
   COLORING: You MUST use flat, stylized vector colors that match the subject's ORIGINAL natural skin tones and clothing colors. The subject should remain recognizable and distinct from the background.

2. THE BACKGROUND: Fill 100% of the background area with an extremely dense, chaotic, and whimsical composition of hand-drawn doodles (swirls, stars, geometric shapes, tiny monsters, flowers).
   COLORING: The background doodles MUST only use shades of ${palette.shades}. Incorporate subtle highlights of ${palette.tertiary}.

3. COMPOSITION: The subject must be clearly layered in front of the background. No doodles should overlap or cross over the subject's face or body.

FINAL OUTPUT: A single, clean, high-resolution graphic art piece. Do not include any photographic textures or realistic shadows. The subject is original-colored vector art, and the background is monochromatic ${palette.label} doodle art.`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: imageBase64, mimeType } },
          { text: fullPrompt }
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1"
        }
      }
    });

    let resultImageUrl = '';
    const candidate = response.candidates?.[0];
    if (candidate?.content?.parts) {
      for (const part of candidate.content.parts) {
        if (part.inlineData?.data) {
          resultImageUrl = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }
    }

    if (!resultImageUrl) {
      throw new Error("Gemini failed to generate an image part. Please check the prompt or image content.");
    }

    return resultImageUrl;
  }
}

import React, { useState, useMemo, useEffect } from 'react';
import { Header } from './components/Header';
import { ImageUploadArea } from './components/ImageUploadArea';
import { ColorSelector } from './components/ColorSelector';
import { ResultDisplay } from './components/ResultDisplay';
import { ImageManager } from './components/ImageManager';
import { WebcamCapture } from './components/WebcamCapture';
import { GeminiService } from './services/geminiService';
import { AppStatus, ImageItem } from './types';
import { COLOR_PALETTES, APP_NAME } from './constants';

export default function App() {
  const [activeTab, setActiveTab] = useState<'manager' | 'gallery'>('manager');
  const [status, setStatus] = useState<AppStatus>('idle');
  const [items, setItems] = useState<ImageItem[]>([]);
  const [selectedColorIds, setSelectedColorIds] = useState<string[]>([COLOR_PALETTES[4].id]); // Default Blue
  const [isWebcamOpen, setIsWebcamOpen] = useState(false);

  const handleUpload = (newItems: ImageItem[]) => {
    setItems(prev => [...prev, ...newItems]);
    setActiveTab('manager');
  };

  const handleWebcamCapture = (base64: string) => {
    const newItem: ImageItem = {
      id: `cam-${Date.now()}`,
      base64,
      mimeType: 'image/png',
      name: `Webcam Capture ${new Date().toLocaleTimeString()}`,
      status: 'pending',
      selected: true
    };
    handleUpload([newItem]);
  };

  const toggleSelect = (id: string) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, selected: !item.selected } : item));
  };

  const handleToggleColor = (id: string) => {
    setSelectedColorIds(prev => {
      if (prev.includes(id)) {
        if (prev.length === 1) return prev;
        return prev.filter(c => c !== id);
      }
      return [...prev, id];
    });
  };

  const handleBatchAction = (action: 'all' | 'none' | 'clear') => {
    if (action === 'all') setItems(prev => prev.map(i => i.isResult ? i : { ...i, selected: true }));
    else if (action === 'none') setItems(prev => prev.map(i => i.isResult ? i : { ...i, selected: false }));
    else if (action === 'clear') {
      setItems(prev => prev.filter(i => i.isResult));
      if (status === 'completed') setStatus('idle');
    }
  };

  const handleRandomizeColors = () => {
    const available = selectedColorIds.length > 0 ? selectedColorIds : COLOR_PALETTES.map(p => p.id);
    setItems(prev => prev.map(item => {
      if (item.selected && !item.isResult) {
        const randomId = available[Math.floor(Math.random() * available.length)];
        return { ...item, assignedColorId: randomId };
      }
      return item;
    }));
  };

  const uploads = useMemo(() => items.filter(i => !i.isResult), [items]);
  const galleryResults = useMemo(() => items.filter(i => i.isResult), [items]);
  const selectedUploads = useMemo(() => uploads.filter(i => i.selected), [uploads]);

  const handleGenerate = async () => {
    if (selectedUploads.length === 0) return;

    setStatus('processing');
    setActiveTab('gallery');

    const gemini = GeminiService.getInstance();

    // 1. Create result placeholders
    const pendingResults: ImageItem[] = selectedUploads.map(upload => {
      const assignedId = upload.assignedColorId || (selectedColorIds[Math.floor(Math.random() * selectedColorIds.length)]);
      return {
        ...upload,
        id: `res-${Date.now()}-${Math.random().toString(36).substring(2, 7)}`,
        status: 'pending',
        isResult: true,
        assignedColorId: assignedId,
        selected: false
      };
    });

    setItems(prev => [...prev, ...pendingResults]);

    // 2. Sequential processing
    for (const resultEntry of pendingResults) {
      setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'processing' } : it));

      const palette = COLOR_PALETTES.find(c => c.id === resultEntry.assignedColorId) || COLOR_PALETTES[0];

      try {
        const generatedUrl = await gemini.transformToDoodle(resultEntry.base64, resultEntry.mimeType, palette);
        setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'success', resultUrl: generatedUrl } : it));
      } catch (err) {
        console.error("Art generation failed:", err);
        setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'error', error: String(err) } : it));
      }
    }

    setStatus('completed');
  };

  return (
    <div className="min-h-screen pb-32 selection:bg-indigo-100">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">

          {/* Controls Panel */}
          <section className="lg:col-span-4 flex flex-col space-y-6 lg:sticky lg:top-32">
            <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
              <h2 className="text-xl font-jakarta font-bold mb-6 flex items-center">
                <span className="w-8 h-8 rounded-full bg-indigo-500 text-white flex items-center justify-center text-[10px] font-black mr-3 shadow-sm">01</span>
                Add Your Photos
              </h2>
              <ImageUploadArea onUpload={handleUpload} onWebcamClick={() => setIsWebcamOpen(true)} itemCount={uploads.length} />
            </div>

            <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
              <h2 className="text-xl font-jakarta font-bold mb-2 flex items-center">
                <span className="w-8 h-8 rounded-full bg-purple-500 text-white flex items-center justify-center text-[10px] font-black mr-3 shadow-sm">02</span>
                Doodle Palettes
              </h2>
              <p className="text-xs text-slate-400 mb-6 font-medium">Select one or more for varied results.</p>
              <ColorSelector selectedIds={selectedColorIds} onToggle={handleToggleColor} disabled={status === 'processing'} />

              <button 
                onClick={handleRandomizeColors}
                disabled={selectedUploads.length === 0 || status === 'processing'}
                className="mt-8 w-full py-4 px-4 bg-slate-50 border border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:bg-slate-100 hover:text-indigo-600 transition-all flex items-center justify-center space-x-2 disabled:opacity-50 disabled:pointer-events-none"
              >
                <span>🔀 Shuffle Assigned Colors</span>
              </button>
            </div>

            <button
              onClick={handleGenerate}
              disabled={selectedUploads.length === 0 || status === 'processing'}
              className={`group w-full py-6 rounded-3xl font-extrabold text-xl text-white shadow-2xl transition-all active:scale-95 disabled:bg-slate-200 disabled:shadow-none relative overflow-hidden ${
                status === 'processing' ? 'cursor-wait' : 'hover:shadow-indigo-200'
              }`}
              style={{ 
                backgroundColor: selectedUploads.length > 0 
                  ? (COLOR_PALETTES.find(c => c.id === selectedColorIds[0])?.hex || '#6366f1') 
                  : '#cbd5e1' 
              }}
            >
              <div className="relative z-10 flex items-center justify-center space-x-3">
                {status === 'processing' && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>}
                <span>{status === 'processing' ? 'Creating Magic...' : `Generate ${selectedUploads.length} Illustrations`}</span>
              </div>
              {status !== 'processing' && (
                <div className="absolute inset-0 bg-white/10 translate-y-full group-hover:translate-y-0 transition-transform"></div>
              )}
            </button>
          </section>

          {/* Viewer Panel */}
          <section className="lg:col-span-8">
            <div className="bg-white p-8 sm:p-12 rounded-[50px] shadow-2xl shadow-indigo-50/50 min-h-[750px] border border-slate-50">
              <div className="flex items-center space-x-2 mb-12 bg-slate-100/50 p-2 rounded-2xl w-fit">
                <button 
                  onClick={() => setActiveTab('manager')} 
                  className={`px-8 py-3 rounded-xl text-sm font-bold transition-all ${
                    activeTab === 'manager' ? 'bg-white text-slate-900 shadow-xl shadow-slate-200/50 transform scale-105' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  Workspace
                </button>
                <button 
                  onClick={() => setActiveTab('gallery')} 
                  className={`px-8 py-3 rounded-xl text-sm font-bold transition-all relative ${
                    activeTab === 'gallery' ? 'bg-white text-slate-900 shadow-xl shadow-slate-200/50 transform scale-105' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  Gallery
                  {galleryResults.length > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-5 w-5">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                      <span className="relative inline-flex rounded-full h-5 w-5 bg-indigo-500 text-[9px] text-white items-center justify-center font-black">{galleryResults.length}</span>
                    </span>
                  )}
                </button>
              </div>

              <div className="transition-all duration-500">
                {activeTab === 'manager' ? (
                  <ImageManager 
                    items={uploads} 
                    onToggleSelect={toggleSelect} 
                    onBatchAction={handleBatchAction} 
                  />
                ) : (
                  <ResultDisplay 
                    items={galleryResults} 
                    onReset={() => setItems(prev => prev.filter(i => !i.isResult))} 
                    isProcessing={status === 'processing'} 
                  />
                )}
              </div>
            </div>
          </section>
        </div>
      </main>

      {/* Floating UI */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur text-white px-8 py-4 rounded-full shadow-2xl text-[10px] font-black uppercase tracking-[0.3em] flex items-center space-x-6 border border-white/10 z-[60] hover:bg-slate-900 transition-colors">
        <div className="flex items-center space-x-2">
          <kbd className="px-2 py-1 bg-white/20 rounded-lg border border-white/10 font-sans">CMD</kbd>
          <span className="opacity-30">+</span>
          <kbd className="px-2 py-1 bg-white/20 rounded-lg border border-white/10 font-sans">V</kbd>
        </div>
        <span className="opacity-20 font-light">|</span>
        <span className="animate-pulse">Paste Anywhere to Upload</span>
      </div>

      {isWebcamOpen && (
        <WebcamCapture 
          onCapture={handleWebcamCapture} 
          onClose={() => setIsWebcamOpen(false)} 
        />
      )}
    </div>
  );
}

