    }
  }, []);

  const handleRandomizeColors = useCallback(() => {
    const pool = selectedColorIds.length > 0 ? selectedColorIds : COLOR_PALETTES.map(p => p.id);

    setItems(prev => {
      // If any items are selected, only randomize those. Otherwise, randomize all non-results.
      const hasSelection = prev.some(i => i.selected && !i.isResult);
      return prev.map(item => {
        if (!item.isResult && (hasSelection ? item.selected : true)) {
          const randomId = pool[Math.floor(Math.random() * pool.length)];
          return { ...item, assignedColorId: randomId };
        }
        return item;
      });
    });
  }, [selectedColorIds]);

  const uploads = useMemo(() => items.filter(i => !i.isResult), [items]);
  const galleryResults = useMemo(() => items.filter(i => i.isResult), [items]);
  const selectedUploads = useMemo(() => uploads.filter(i => i.selected), [uploads]);

  const handleGenerate = async () => {
    if (selectedUploads.length === 0) return;

    setStatus('processing');
    setActiveTab('gallery');

    const gemini = GeminiService.getInstance();

    // Create execution queue
    const executionQueue: ImageItem[] = selectedUploads.map(upload => {
      // Ensure every image has a color assigned
      const finalColorId = upload.assignedColorId || selectedColorIds[Math.floor(Math.random() * selectedColorIds.length)];
      return {
        ...upload,
        id: `res-${Date.now()}-${Math.random().toString(36).substring(2, 7)}`,
        status: 'pending',
        isResult: true,
        assignedColorId: finalColorId,
        selected: false
      };
    });

    setItems(prev => [...prev, ...executionQueue]);

    for (const resultEntry of executionQueue) {
      setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'processing' } : it));

      const palette = COLOR_PALETTES.find(c => c.id === resultEntry.assignedColorId) || COLOR_PALETTES[0];

      try {
        const generatedUrl = await gemini.transformToDoodle(resultEntry.base64, resultEntry.mimeType, palette);
        setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'success', resultUrl: generatedUrl } : it));
      } catch (err) {
        setItems(prev => prev.map(it => it.id === resultEntry.id ? { ...it, status: 'error', error: String(err) } : it));
      }
    }

    setStatus('completed');
  };

  return (
    <div className="min-h-screen pb-32">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          <section className="lg:col-span-4 space-y-6 lg:sticky lg:top-32">
            <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
              <h2 className="text-xl font-jakarta font-bold mb-6 flex items-center">
                <span className="w-8 h-8 rounded-full bg-indigo-500 text-white flex items-center justify-center text-[10px] font-black mr-3">01</span>
                Image Input
              </h2>
              <ImageUploadArea onUpload={handleUpload} onWebcamClick={() => setIsWebcamOpen(true)} itemCount={uploads.length} />
            </div>

            <div className="bg-white p-8 rounded-[40px] shadow-sm border border-slate-100">
              <h2 className="text-xl font-jakarta font-bold mb-2 flex items-center">
                <span className="w-8 h-8 rounded-full bg-purple-500 text-white flex items-center justify-center text-[10px] font-black mr-3">02</span>
                Artist Palette
              </h2>
              <p className="text-xs text-slate-400 mb-6 font-medium">Select multiple to enable randomization.</p>
              <ColorSelector selectedIds={selectedColorIds} onToggle={handleToggleColor} disabled={status === 'processing'} />

              <button 
                onClick={handleRandomizeColors}
                disabled={uploads.length === 0 || status === 'processing'}
                className="mt-8 w-full py-4 bg-slate-50 border border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:bg-indigo-50 hover:text-indigo-600 transition-all active:scale-95 disabled:opacity-50"
              >
                🔀 Randomize Queue Colors
              </button>
            </div>

            <button
              onClick={handleGenerate}
              disabled={selectedUploads.length === 0 || status === 'processing'}
              className="w-full py-6 rounded-3xl font-extrabold text-xl text-white shadow-2xl transition-all active:scale-95 disabled:bg-slate-200 disabled:shadow-none bg-indigo-600 hover:bg-indigo-700"
            >
              {status === 'processing' ? (
                <div className="flex items-center justify-center space-x-3">
                  <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
                  <span>Generating...</span>
                </div>
              ) : `Process ${selectedUploads.length} Images`}
            </button>
          </section>

          <section className="lg:col-span-8">
            <div className="bg-white p-8 sm:p-12 rounded-[50px] shadow-2xl shadow-indigo-100/50 min-h-[800px] border border-slate-50 relative overflow-hidden">
              <div className="flex items-center space-x-2 mb-10 bg-slate-100/50 p-2 rounded-2xl w-fit">
                <button 
                  onClick={() => setActiveTab('manager')} 
                  className={`px-8 py-3 rounded-xl text-sm font-bold transition-all ${
                    activeTab === 'manager' ? 'bg-white text-slate-900 shadow-md transform scale-105' : 'text-slate-400'
                  }`}
                >
                  Workspace
                </button>
                <button 
                  onClick={() => setActiveTab('gallery')} 
                  className={`px-8 py-3 rounded-xl text-sm font-bold transition-all relative ${
                    activeTab === 'gallery' ? 'bg-white text-slate-900 shadow-md transform scale-105' : 'text-slate-400'
                  }`}
                >
                  Gallery
                  {galleryResults.length > 0 && (
                    <span className="absolute -top-1 -right-1 flex h-5 w-5 rounded-full bg-indigo-500 text-[9px] text-white items-center justify-center font-black">
                      {galleryResults.length}
                    </span>
                  )}
                </button>
              </div>

              {activeTab === 'manager' ? (
                <ImageManager 
                  items={uploads} 
                  onToggleSelect={toggleSelect} 
                  onBatchAction={handleBatchAction} 
                  onRandomize={handleRandomizeColors}
                />
              ) : (
                <ResultDisplay 
                  items={galleryResults} 
                  onReset={() => setItems(prev => prev.filter(i => !i.isResult))} 
                  isProcessing={status === 'processing'} 
                />
              )}
            </div>
          </section>
        </div>
      </main>

      {/* Floating Prompt */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-slate-900/90 backdrop-blur text-white px-8 py-4 rounded-full shadow-2xl text-[10px] font-black uppercase tracking-[0.3em] flex items-center space-x-6 border border-white/10 z-[60] animate-float">
        <div className="flex items-center space-x-2">
          <kbd className="px-2 py-1 bg-white/20 rounded-lg">CMD</kbd>
          <span className="opacity-30">+</span>
          <kbd className="px-2 py-1 bg-white/20 rounded-lg">V</kbd>
        </div>
        <span className="opacity-20">|</span>
        <span>Paste to Upload</span>
      </div>

      {isWebcamOpen && <WebcamCapture onCapture={handleWebcamCapture} onClose={() => setIsWebcamOpen(false)} />}
    </div>
  );
}

