              )}

              {/* Selection Checkmark */}
              {item.selected && (
                <div className="absolute top-2 right-2 bg-indigo-500 rounded-xl p-1.5 shadow-lg transform scale-110 z-20">
                  <svg className="w-3.5 h-3.5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="4" d="M5 13l4 4L19 7" />
                  </svg>
                </div>
              )}

              {/* Overlay for Color Glow */}
              {assignedColor && (
                <div 
                  className="absolute inset-0 pointer-events-none opacity-20 group-hover:opacity-40 transition-opacity"
                  style={{ background: `radial-gradient(circle at bottom right, ${assignedColor.hex} 0%, transparent 60%)` }}
                />
              )}
            </div>
          );
        })}
      </div>
    )}
  </div>
);

