    const successfulItems = items.filter(item => item.status === 'success' && item.resultUrl);
    successfulItems.forEach((item, index) => {
      // Small timeout to help browser handle multiple download requests
      setTimeout(() => {
        const link = document.createElement('a');
        link.href = item.resultUrl!;
        link.download = `VividDoodle-${item.id}.png`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      }, index * 300);
    });
  };

